import Profile2 from './components/Profile2'
import users from './user.json';

export default function App() {
  return 
   {users.map((user,i) =>
    <div>

      <Profile2 
          key={i}
          name={user.name}
          tag={user.tag}
          location={user.location}
          avatar={user.avatar}
          stats={user.stats}
      />

    </div> 
    )}  
  }
